#include <vector>
#include <queue>
using namespace std;

long long solve(vector<vector<long long>> grid, long long k) {
    int m = grid.size();
    int n = grid[0].size();
    long long count = 0;

    for (int i = 0; i < m; ++i) {
        for (int j = 0; j < n; ++j) {
            if (grid[i][j] != 0) {
                queue<pair<int, int>> q;
                q.push({i, j});
                long long sum = 0;
                while (!q.empty()) {
                    auto [x, y] = q.front();
                    q.pop();
                    sum += grid[x][y];
                    grid[x][y] = 0;
                    int dx[] = {-1, 1, 0, 0};
                    int dy[] = {0, 0, -1, 1};
                    for (int d = 0; d < 4; ++d) {
                        int nx = x + dx[d];
                        int ny = y + dy[d];
                        if (nx >= 0 && nx < m && ny >= 0 && ny < n && grid[nx][ny] != 0) {
                            q.push({nx, ny});
                        }
                    }
                }
                if (sum % k == 0) {
                    count++;
                }
            }
        }
    }
    return count;
}
```

